    82→func (c *configMapManager) GetConfigMap(namespace, name string) (*v1.ConfigMap, error) {
    83→	object, err := c.manager.GetObject(namespace, name)
    84→	if err != nil {
    85→		return nil, err
    86→	}
    87→	if configmap, ok := object.(*v1.ConfigMap); ok {
