    37→// strategy implements behavior for Secret objects
    38→type strategy struct {
    39→	runtime.ObjectTyper
    40→	names.NameGenerator
    41→}
    42→
    43→// Strategy is the default logic that applies when creating and updating Secret
    44→// objects via the REST API.
    45→var Strategy = strategy{legacyscheme.Scheme, names.SimpleNameGenerator}
    46→
    47→var _ = rest.RESTCreateStrategy(Strategy)
    48→
    49→var _ = rest.RESTUpdateStrategy(Strategy)
