    64→// WarningsOnCreate returns warnings for the creation of the given object.
    65→func (strategy) WarningsOnCreate(ctx context.Context, obj runtime.Object) []string {
    66→	return warningsForSecret(obj.(*api.Secret))
    67→}
    68→
    69→func (strategy) Canonicalize(obj runtime.Object) {
    70→}
    71→
    72→func (strategy) AllowCreateOnUpdate() bool {
    73→	return false
    74→}
    75→
    76→func (strategy) PrepareForUpdate(ctx context.Context, obj, old runtime.Object) {
    77→	newSecret := obj.(*api.Secret)
    78→	oldSecret := old.(*api.Secret)
    79→
    80→	// this is weird, but consistent with what the validatedUpdate function used to do.
    81→	if len(newSecret.Type) == 0 {
    82→		newSecret.Type = oldSecret.Type
    83→	}
    84→
    85→	dropDisabledFields(newSecret, oldSecret)
    86→}
