   104→// GetAttrs returns labels and fields of a given object for filtering purposes.
   105→func GetAttrs(obj runtime.Object) (labels.Set, fields.Set, error) {
   106→	secret, ok := obj.(*api.Secret)
   107→	if !ok {
   108→		return nil, nil, fmt.Errorf("not a secret")
   109→	}
   110→	return labels.Set(secret.Labels), SelectableFields(secret), nil
   111→}
   112→
   113→// Matcher returns a selection predicate for a given label and field selector.
   114→func Matcher(label labels.Selector, field fields.Selector) pkgstorage.SelectionPredicate {
   115→	return pkgstorage.SelectionPredicate{
   116→		Label:    label,
   117→		Field:    field,
   118→		GetAttrs: GetAttrs,
   119→	}
   120→}
